# Simulating a database
account_database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

def check_email_match(payload):
    """
    Checks if a provided email matches the one in the database for a given user.

    Args:
        payload: A dictionary containing a 'body' field with user ID and email to verify

    Returns:
        Boolean: True if the email exists and matches, False otherwise
    """
    if not payload or 'body' not in payload:
        return False

    body = payload['body']

    if not isinstance(body, dict) or 'user_id' not in body or 'email' not in body:
        return False

    user_id = body['user_id']
    email_to_verify = body['email']

    if user_id in account_database.get('users', {}):
        stored_email = account_database['users'][user_id].get('email')
        return stored_email == email_to_verify

    return False

# Simulating a database
account_database = {
    "users": {
        "1": {"email": "old.email@example.com"},
    }
}

# Expected CSRF token
VALID_TOKEN = "secure_csrf_token"


def validate_csrf_token(token: str) -> bool:
    """Validate the CSRF token against the expected value."""
    return token == VALID_TOKEN


def update_user_email_in_db(user_id: str, new_email: str) -> bool:
    """Update user's email in the database if user exists."""
    if user_id not in account_database["users"]:
        return False

    account_database["users"][user_id]["email"] = new_email
    return True


def edit_user_email(payload: dict) -> bool:
    # Guard clause: Check payload structure
    if not payload or "headers" not in payload or "body" not in payload:
        return False

    # Guard clause: Validate CSRF token
    csrf_token = payload["headers"].get("X-CSRF-Token", "")
    if not validate_csrf_token(csrf_token):
        return False

    # Guard clause: Check required fields
    body = payload["body"]
    user_id = body.get("user_id")
    new_email = body.get("new_email")

    if not user_id or not new_email:
        return False

    # Update the database
    return update_user_email_in_db(user_id, new_email)
